import{_ as t,o as s,c as e,a as i}from"./app-2a089349.js";const n={},r=i('<h1 id="display-subscription-status-invoices-and-active-subscriptions-in-the-admin-screen" tabindex="-1"><a class="header-anchor" href="#display-subscription-status-invoices-and-active-subscriptions-in-the-admin-screen" aria-hidden="true">#</a> Display Subscription Status, Invoices and Active Subscriptions in the Admin screen</h1><p>The Stripe Extension has features that display subscription status, invoices, and active subscriptions on the admin screen. This article will explain how to use the features.</p><h4 id="display-subscription-status" tabindex="-1"><a class="header-anchor" href="#display-subscription-status" aria-hidden="true">#</a> Display Subscription Status</h4><p>When you have successfully set up your Stripe Extension, go to <strong>wp-admin &gt; Users</strong>. Here you&#39;ll see the following subscription statuses for your users:</p><table><thead><tr><th><strong>Active</strong></th><th>displays when the user&#39;s subscription is active</th></tr></thead><tbody><tr><td><strong>Inactive</strong></td><td>displays when the user&#39;s subscription is inactive</td></tr><tr><td><strong>Trialing</strong></td><td>displays when the user&#39;s subscription is trialing</td></tr><tr><td><strong>Canceled</strong></td><td>displays when the user&#39;s subscription is canceled</td></tr><tr><td><strong>Revoked</strong></td><td>displays when the user&#39;s subscription has been revoked after assigning the Stripe customer to another WP account</td></tr><tr><td><strong>Unpaid</strong></td><td>displays when the user&#39;s subscription is unpaid</td></tr><tr><td><strong>Past Due</strong></td><td>displays when the user&#39;s subscription is past due</td></tr><tr><td><strong>Paused</strong></td><td>displays when the user&#39;s subscription is paused</td></tr></tbody></table><p>The &quot; <strong>View on Stripe&quot;</strong> link under each status opens a new tab to your customer&#39;s Stripe overview page</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6c5761280097516451b67/file-6FSaN0cQG0.png" alt=""></p><h4 id="invoices-and-active-subscriptions" tabindex="-1"><a class="header-anchor" href="#invoices-and-active-subscriptions" aria-hidden="true">#</a> Invoices and Active Subscriptions</h4><p>When you edit a user with an <strong>active subscription status</strong> in <strong>wp-admin &gt; Users</strong>, you&#39;ll be able to see the user&#39;s or customer&#39;s subscriptions and invoices table under the <strong>Ultimate Member Stripe</strong> section.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6c64430c1875e8e0675bb/file-GTSL8Mb5xw.png" alt=""></p><p>The invoice table will only display the most recent invoices, not all. You need to click the <strong>&quot;Manage on Stripe&quot;</strong> link, which will open a new tab to the customer overview on Stripe.com.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6c7011280097516451b6a/file-KW4C8CGO3c.png" alt=""></p><p><strong>Note: You may test or create a simulation of how the statuses change when testing your integration with Stripe test clocks. See</strong> <a href="/docs-v3/um-stripe/article/1803-test-your-integration-with-stripe-test-clocks">/docs-v3/um-stripe/article/1803-test-your-integration-with-stripe-test-clocks</a> <strong>for more information.</strong></p>',13),o=[r];function a(c,d){return s(),e("div",null,o)}const u=t(n,[["render",a],["__file","1865-display-subscription-status-invoices-and-active-subscriptions-in-the-admin-screen.html.vue"]]);export{u as default};
